'use client';

import type { TransactionStatus, Currency } from '@/types';

interface TransactionFiltersProps {
  statusFilter:   TransactionStatus | 'ALL';
  currencyFilter: Currency | 'ALL';
  searchQuery:    string;
  onStatusChange:   (v: TransactionStatus | 'ALL') => void;
  onCurrencyChange: (v: Currency | 'ALL') => void;
  onSearchChange:   (v: string) => void;
}

const STATUS_OPTIONS: { value: TransactionStatus | 'ALL'; label: string }[] = [
  { value: 'ALL',             label: 'All statuses'   },
  { value: 'COMPLETED',       label: 'Completed'      },
  { value: 'USDC_SENT',       label: 'Bridging'       },
  { value: 'NAIRA_DEBITED',   label: 'Naira debited'  },
  { value: 'INITIATED',       label: 'Initiated'      },
  { value: 'CEDIS_CREDITED',  label: 'Crediting'      },
  { value: 'FAILED',          label: 'Failed'         },
];

const CURRENCY_OPTIONS: { value: Currency | 'ALL'; label: string }[] = [
  { value: 'ALL', label: 'All currencies' },
  { value: 'NGN', label: '🇳🇬 NGN'        },
  { value: 'GHS', label: '🇬🇭 GHS'        },
];

export function TransactionFilters({
  statusFilter,
  currencyFilter,
  searchQuery,
  onStatusChange,
  onCurrencyChange,
  onSearchChange,
}: TransactionFiltersProps) {
  return (
    <div className="flex flex-col sm:flex-row gap-3">
      {/* Search */}
      <div className="relative flex-1">
        <svg className="absolute left-3.5 top-1/2 -translate-y-1/2 text-zinc-600" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <circle cx="11" cy="11" r="8"/>
          <line x1="21" y1="21" x2="16.65" y2="16.65"/>
        </svg>
        <input
          type="text"
          placeholder="Search recipient, narration..."
          value={searchQuery}
          onChange={(e) => onSearchChange(e.target.value)}
          className="w-full rounded-xl border border-[#1e1e32] bg-[#0f0f1a] pl-9 pr-4 py-2.5 text-sm text-zinc-100 placeholder:text-zinc-700 outline-none focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/20 transition-all"
        />
      </div>

      {/* Status filter */}
      <select
        value={statusFilter}
        onChange={(e) => onStatusChange(e.target.value as TransactionStatus | 'ALL')}
        className="rounded-xl border border-[#1e1e32] bg-[#0f0f1a] px-3 py-2.5 text-sm text-zinc-400 outline-none focus:border-indigo-500/50 transition-all cursor-pointer appearance-none min-w-[140px]"
      >
        {STATUS_OPTIONS.map((o) => (
          <option key={o.value} value={o.value} className="bg-[#0f0f1a]">{o.label}</option>
        ))}
      </select>

      {/* Currency filter */}
      <select
        value={currencyFilter}
        onChange={(e) => onCurrencyChange(e.target.value as Currency | 'ALL')}
        className="rounded-xl border border-[#1e1e32] bg-[#0f0f1a] px-3 py-2.5 text-sm text-zinc-400 outline-none focus:border-indigo-500/50 transition-all cursor-pointer appearance-none min-w-[140px]"
      >
        {CURRENCY_OPTIONS.map((o) => (
          <option key={o.value} value={o.value} className="bg-[#0f0f1a]">{o.label}</option>
        ))}
      </select>
    </div>
  );
}
